module freq_div(
    input CLK_in,
    input RST,
    output CLK_50,
    output CLK_10,
    output CLK_1
);

reg [2:0] counter_50 = 0;
reg [4:0] counter_10 = 0;
reg [9:0] counter_1 = 0;

always @(posedge CLK_in or negedge RST) begin
    if (!RST) begin
        counter_50 <= 0;
        counter_10 <= 0;
        counter_1 <= 0;
    end
    else begin
        counter_50 <= counter_50 + 1;
        counter_10 <= counter_10 + 1;
        counter_1 <= counter_1 + 1;
    end
end

assign CLK_50 = counter_50[0];
assign CLK_10 = counter_10[3];
assign CLK_1 = counter_1[6];

endmodule
